// Collect mapped events from every feed, then: (a) keep only the near-term
// window — raw ICS feeds dump full history; (b) guarantee a title, since ICS
// events without SUMMARY would 422 the whole batch; (c) DEDUPE across feeds by
// the bare UID — the same event often appears on more than one calendar
// (personal mirrors work/Outlook invites), and the per-feed namespace prefix
// would otherwise make them look distinct. First feed wins (order: personal,
// work, outlook); the dropped namespace's stale row is pruned on next sync.
const now = Date.now();
const FROM = now - 60 * 60 * 1000;
const TO = now + 36 * 60 * 60 * 1000;
const seen = new Set();
const events = [];
for (const item of $input.all()) {
  const e = item.json;
  const t = Date.parse(e.start_at);
  if (Number.isNaN(t) || t < FROM || t > TO) continue;
  const uid = String(e.external_id || '').replace(/^[^:]+:/, '');
  if (uid) { if (seen.has(uid)) continue; seen.add(uid); }
  events.push({ ...e, title: (e.title && String(e.title).trim()) || '(busy)' });
}
return [{ json: { events } }];

